fn extract_relations(
    file_path: &str,
    source: &str,
    extension: &str,
    chunks: &[CodeChunk],
    module_map: Option<&RustModuleMap>,
) -> Vec<CodeRelation> {
    if chunks.is_empty() {
        return vec![];
    }
    match extension {
        "rs" => extract_rust_relations(file_path, source, chunks, module_map),
        "js" | "jsx" | "ts" | "tsx" => extract_js_ts_relations(file_path, source, extension, chunks),
        "py" => extract_python_relations(file_path, source, chunks),
        _ => vec![],
    }
}
```

